const ChatPanel: React.FC = () => {
  const [chats, setChats] = useState<ChatItem[]>([
    { id: '1', name: 'John Doe', lastMessage: 'Hey there!', timestamp: '10:30 AM', isFavorite: false },
    { id: '2', name: 'Jane Smith', lastMessage: 'See you tomorrow', timestamp: '9:15 AM', isFavorite: true },
