import json
import os
import threading
from typing import Dict, Optional
from pathlib import Path

class GroupChatManager:
    """Central storage manager for group chat names with conflict resolution."""

    def __init__(self, storage_path: str = "data/group_chats.json"):
        self.storage_path = Path(storage_path)
        self.storage_path.parent.mkdir(parents=True, exist_ok=True)
        self.lock = threading.Lock()
        self._ensure_storage()

    def _ensure_storage(self):
        """Ensure storage file exists with proper structure."""
        if not self.storage_path.exists():
            with self.lock:
                if not self.storage_path.exists():  # Double-check after acquiring lock
                    self.storage_path.write_text(json.dumps({
                        "chats": {},
                        "name_index": {}
                    }, indent=2))

    def _load_data(self) -> Dict:
        """Load group chat data from storage."""
        try:
            return json.loads(self.storage_path.read_text())
        except (FileNotFoundError, json.JSONDecodeError):
            return {"chats": {}, "name_index": {}}

    def _save_data(self, data: Dict):
        """Save group chat data to storage."""
        self.storage_path.write_text(json.dumps(data, indent=2))

    def create_group_chat(self, chat_id: str, chat_name: str) -> Dict:
        """
        Create a new group chat with conflict resolution.

        Returns dict with 'success' boolean and 'chat_name' (possibly modified).
        """
        with self.lock:
            data = self._load_data()

            # Check if chat_id already exists
            if chat_id in data["chats"]:
                return {
                    "success": True, 
                    "chat_name": data["chats"][chat_id]["name"],
                    "message": "Chat already exists"
                }

            # Resolve naming conflicts
            original_name = chat_name
            counter = 1
            while chat_name in data["name_index"]:
                chat_name = f"{original_name} ({counter})"
                counter += 1

            # Store chat info
            data["chats"][chat_id] = {
                "name": chat_name,
                "created_at": os.time() if hasattr(os, 'time') else 0
            }
            data["name_index"][chat_name] = chat_id

            self._save_data(data)

            return {
                "success": True,
                "chat_name": chat_name,
                "message": "Chat created successfully"
            }

    def get_chat_name(self, chat_id: str) -> Optional[str]:
        """Get the name of a group chat by ID."""
        data = self._load_data()
        chat = data["chats"].get(chat_id)
        return chat["name"] if chat else None

    def list_all_chats(self) -> Dict[str, str]:
        """List all group chats (ID -> name mapping)."""
        data = self._load_data()
        return {chat_id: chat["name"] for chat_id, chat in data["chats"].items()}

    def delete_chat(self, chat_id: str) -> bool:
        """Delete a group chat by ID."""
        with self.lock:
            data = self._load_data()
            if chat_id in data["chats"]:
                chat_name = data["chats"][chat_id]["name"]
                del data["chats"][chat_id]
                if chat_name in data["name_index"]:
                    del data["name_index"][chat_name]
                self._save_data(data)
                return True
            return False

# MARKER_102_2_START
# Global instance for the application
group_chat_manager = GroupChatManager()

def get_group_chat_manager():
    """Get the global group chat manager instance."""
    return group_chat_manager
# MARKER_102_2_END
