import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import { ChatNode } from '../types/chat'

interface ChatTreeState {
  chats: ChatNode[]
  starredChats: Set<string>
  // MARKER_102.2: Add sort order state
  sortOrder: 'recent' | 'starred-first' | 'alphabetical'
  addChat: (chat: ChatNode) => void
  removeChat: (id: string) => void
  updateChat: (id: string, chat: Partial<ChatNode>) => void
  // MARKER_102.2: Add methods for starring and sorting
  starChat: (id: string) => void
  unstarChat: (id: string) => void
  setSortOrder: (order: 'recent' | 'starred-first' | 'alphabetical') => void
  // MARKER_102.2: Method to get sorted chats
  getSortedChats: () => ChatNode[]
}

// MARKER_102.2_START
export const useChatTreeStore = create<ChatTreeState>()(
  persist(
    (set, get) => ({
      chats: [],
      starredChats: new Set(),
      sortOrder: 'starred-first',

      addChat: (chat) => set((state) => ({ 
        chats: [...state.chats, chat] 
      })),

      removeChat: (id) => set((state) => ({ 
        chats: state.chats.filter(chat => chat.id !== id) 
      })),

      updateChat: (id, updatedChat) => set((state) => ({
        chats: state.chats.map(chat => 
          chat.id === id ? { ...chat, ...updatedChat } : chat
        )
      })),

      starChat: (id) => set((state) => ({
        starredChats: new Set(state.starredChats).add(id)
      })),

      unstarChat: (id) => set((state) => {
        const newStarred = new Set(state.starredChats)
        newStarred.delete(id)
        return { starredChats: newStarred }
      }),

      setSortOrder: (order) => set({ sortOrder: order }),

      getSortedChats: () => {
        const { chats, starredChats, sortOrder } = get()
        const chatArray = [...chats]

        switch (sortOrder) {
          case 'starred-first':
            // Sort by starred status first, then by updated_at
            return chatArray.sort((a, b) => {
              const aStarred = starredChats.has(a.id) ? 1 : 0
              const bStarred = starredChats.has(b.id) ? 1 : 0

              // If one is starred and the other isn't, starred comes first
              if (aStarred !== bStarred) {
                return bStarred - aStarred
              }

              // If both starred or both not starred, sort by updated_at
              const aTime = new Date(a.updated_at || a.created_at).getTime()
              const bTime = new Date(b.updated_at || b.created_at).getTime()
              return bTime - aTime
            })

          case 'recent':
            // Sort by updated_at timestamp (newest first)
            return chatArray.sort((a, b) => {
              const aTime = new Date(a.updated_at || a.created_at).getTime()
              const bTime = new Date(b.updated_at || b.created_at).getTime()
              return bTime - aTime
            })

          case 'alphabetical':
            // Sort by display name alphabetically
            return chatArray.sort((a, b) => {
              const aName = a.display_name || a.file_name || 'Untitled'
              const bName = b.display_name || b.file_name || 'Untitled'
              return aName.localeCompare(bName)
            })

          default:
            return chatArray
        }
      }
    }),
    {
      name: 'chat-tree-storage',
      partialize: (state) => ({ 
        chats: state.chats, 
        starredChats: Array.from(state.starredChats),
        sortOrder: state.sortOrder
      }),
      merge: (persisted, current) => ({
        ...current,
        ...persisted,
        starredChats: new Set(persisted.starredChats)
      })
    }
  )
)
// MARKER_102.2_END
