import { ArtifactResponse, FetchArtifactsParams } from '../types/artifact';

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL || '/api';

export class ArtifactClient {
  async fetchHighlightArtifacts(params: FetchArtifactsParams): Promise<ArtifactResponse> {
    const queryParams = new URLSearchParams({
      limit: params.limit?.toString() || '10',
      offset: params.offset?.toString() || '0',
      ...(params.taskId && { taskId: params.taskId })
    });

    const response = await fetch(`${API_BASE_URL}/highlight_artifacts?${queryParams}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch artifacts: ${response.statusText}`);
    }

    return response.json();
  }

  async getArtifactById(id: string): Promise<HighlightArtifact> {
    const response = await fetch(`${API_BASE_URL}/highlight_artifacts/${id}`);

    if (!response.ok) {
      throw new Error(`Failed to fetch artifact: ${response.statusText}`);
    }

    return response.json();
  }
}

export const artifactClient = new ArtifactClient();
