from typing import Dict, List, Any, Optional
from fastapi import APIRouter, HTTPException, Depends
from pydantic import BaseModel
from src.knowledge_graph.graph_manager import GraphManager
from src.layout.layout_utils import LayoutUtils
from src.api.dependencies import get_graph_manager

router = APIRouter(prefix="/layout", tags=["layout"])

class ButtonAction(BaseModel):
    action_type: str
    target_id: str
    parameters: Optional[Dict[str, Any]] = None

class LayoutRequest(BaseModel):
    layout_type: str
    nodes: List[Dict[str, Any]]
    edges: List[Dict[str, Any]]

class LayoutResponse(BaseModel):
    nodes: List[Dict[str, Any]]
    edges: List[Dict[str, Any]]

@router.post("/knowledge")
async def generate_knowledge_layout(
    request: LayoutRequest,
    graph_manager: GraphManager = Depends(get_graph_manager)
):
    """
    Generate layout for knowledge graph visualization
    """
    try:
        # Process the layout request
        layout_utils = LayoutUtils()

        # Handle different layout types
        if request.layout_type == "force_directed":
            result = layout_utils.force_directed_layout(request.nodes, request.edges)
        elif request.layout_type == "hierarchical":
            result = layout_utils.hierarchical_layout(request.nodes, request.edges)
        elif request.layout_type == "circular":
            result = layout_utils.circular_layout(request.nodes, request.edges)
        else:
            # Default to force directed if unknown type
            result = layout_utils.force_directed_layout(request.nodes, request.edges)

        return LayoutResponse(**result)

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Layout generation failed: {str(e)}")

@router.post("/button-action")
async def handle_button_action(
    action: ButtonAction,
    graph_manager: GraphManager = Depends(get_graph_manager)
):
    """
    Handle button actions in the knowledge layout interface
    """
    try:
        # Process different button actions
        if action.action_type == "expand_node":
            # Expand a node and its neighbors
            expanded_nodes, expanded_edges = graph_manager.expand_node(action.target_id)

            # Return updated layout data
            return {
                "nodes": expanded_nodes,
                "edges": expanded_edges,
                "action": "node_expanded"
            }

        elif action.action_type == "collapse_node":
            # Collapse a node and remove its children
            collapsed_nodes, collapsed_edges = graph_manager.collapse_node(action.target_id)

            # Return updated layout data
            return {
                "nodes": collapsed_nodes,
                "edges": collapsed_edges,
                "action": "node_collapsed"
            }

        elif action.action_type == "filter_by_type":
            # Filter nodes by type
            filtered_nodes, filtered_edges = graph_manager.filter_by_type(
                action.target_id, 
                action.parameters.get("node_type", "all")
            )

            return {
                "nodes": filtered_nodes,
                "edges": filtered_edges,
                "action": "filtered_by_type"
            }

        elif action.action_type == "highlight_node":
            # Highlight specific node
            highlighted_nodes = graph_manager.highlight_node(action.target_id)

            return {
                "nodes": highlighted_nodes,
                "action": "node_highlighted"
            }

        else:
            raise HTTPException(status_code=400, detail=f"Unknown action type: {action.action_type}")

    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Button action processing failed: {str(e)}")

# MARKER_102.3_END
