  const { selectedId, nodes } = useStore((state) => ({
    selectedId: state.selectedId,
    nodes: state.nodes,
  }));

  // Ensure button is always interactive
  useEffect(() => {
    const button = inspectButtonRef.current;
    if (button) {
      // Reset any CSS properties that might block interaction
      button.style.pointerEvents = 'auto';
      button.style.visibility = 'visible';
      button.style.display = 'block';
      button.style.zIndex = '1000';
      button.style.position = 'relative';
    }
  }, []);

  const handleInspect = () => {
    if (!selectedId) return;

    const node = nodes[selectedId];
    if (!node) return;

    // Log inspection data to console for debugging
    console.log('Inspecting node:', {
      id: selectedId,
      name: node.name,
      path: node.path,
      type: node.type,
      backendType: node.backendType,
      depth: node.depth,
    });

    setIsInspecting(true);
    setTimeout(() => setIsInspecting(false), 2000);
  };

