Looking at the VoiceButton component, I can see several issues with event listeners and error handling. Let me fix them:

```typescript
// file: client/src/components/voice/VoiceButton.tsx

import { useState, useCallback, useRef, useEffect } from 'react';
import { Mic, MicOff, Volume2, Loader2 } from 'lucide-react';
import { VoiceWave } from './VoiceWave';
import { getSocketUrl } from '../../config/api.config';

interface VoiceButtonProps {
  onTranscript: (text: string) => void;
  disabled?: boolean;
  compact?: boolean;
}

interface VoiceSocket {
  emit: (event: string, data?: any) => void;
  on: (event: string, callback: (data: any) => void) => void;
  off: (event: string, callback?: (data: any) => void) => void;
  connected: boolean;
}

export function VoiceButton({
  onTranscript,
  disabled = false,
  compact = false,
}: VoiceButtonProps) {
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [intensity, setIntensity] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const socketRef = useRef<VoiceSocket | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const eventListenersRef = useRef<Record<string, (data: any) => void>>({});

  // Get socket from global or create connection
  useEffect(() => {
    const getSocket = () => {
      if (typeof window !== 'undefined' && (window as any).io) {
        const io = (window as any).io;
        const socketUrl = getSocketUrl();
        socketRef.current = io(socketUrl, {
          transports: ['websocket', 'polling'],
          reconnection: true,
        });
      }
    };

    getSocket();

    return () => {
      // Properly clean up all socket event listeners
      if (socketRef.current) {
        Object.entries(eventListenersRef.current).forEach(([event, handler]) => {
          socketRef.current?.off(event, handler);
        });
        socketRef.current = null;
      }
    };
  }, []);

  // Socket event listeners with proper cleanup
  useEffect(() => {
    const socket = socketRef.current;
    if (!socket) return;

    // Define event handlers
    const handleTranscribed = (data: { text: string; final: boolean }) => {
      try {
        if (data.text) {
          onTranscript(data.text);
        }
        setIsProcessing(false);
      } catch (err) {
        console.error('[Voice] Error in handleTranscribed:', err);
        setError('Transcription processing error');
      }
    };

    const handleStatus = (data: { status: string }) => {
      try {
        if (data.status === 'speaking') {
          setIsSpeaking(true);
        } else if (data.status === 'idle') {
          setIsSpeaking(false);
          setIsListening(false);
        } else if (data.status === 'listening') {
          setIsListening(true);
        }
      } catch (err) {
        console.error('[Voice] Error in handleStatus:', err);
      }
    };

    const handleError = (data: { error: string }) => {
      try {
        setError(data.error);
        setIsProcessing(false);
        setIsListening(false);
        setTimeout(() => setError(null), 3000);
      } catch (err) {
        console.error('[Voice] Error in handleError:', err);
      }
    };

    // Store handlers for cleanup
    eventListenersRef.current = {
      voice_transcribed: handleTranscribed,
      voice_status: handleStatus,
      voice_error: handleError
    };

    // Attach listeners
    socket.on('voice_transcribed', handleTranscribed);
    socket.on('voice_status', handleStatus);
    socket.on('voice_error', handleError);

    return () => {
      // Clean up listeners properly
      Object.entries(eventListenersRef.current).forEach(([event, handler]) => {
        socket.off(event, handler);
      });
      eventListenersRef.current = {};
    };
  }, [onTranscript]);

  // Audio level analysis for wave intensity
  const analyzeAudio = useCallback((stream: MediaStream) => {
    try {
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      analyserRef.current = audioContextRef.current.createAnalyser();
      const source = audioContextRef.current.createMediaStreamSource(stream);
      source.connect(analyserRef.current);

      analyserRef.current.fftSize = 256;
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);

      const updateIntensity = () => {
        if (!analyserRef.current || !isListening) {
          setIntensity(0);
          return;
        }

        try {
          analyserRef.current.getByteFrequencyData(dataArray);
          const average = dataArray.reduce((a, b) => a + b, 0) / dataArray.length;
          setIntensity(Math.min(1, average / 128));
        } catch (err) {
          console.error('[Voice] Error getting audio data:', err);
          setIntensity(0);
        }

        animationFrameRef.current = requestAnimationFrame(updateIntensity);
      };

      updateIntensity();
    } catch (e) {
      console.error('[Voice] Audio analysis error:', e);
      setError('Audio analysis failed');
    }
  }, [isListening]);

  const startListening = useCallback(async () => {
    if (disabled || isListening || isProcessing) return;

    setError(null);

    try {
      // Request microphone access
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        },
      });

      streamRef.current = stream;

      // Start audio analysis for wave animation
      analyzeAudio(stream);

      // Create MediaRecorder
      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : MediaRecorder.isTypeSupported('audio/mp4') 
        ? 'audio/mp4' 
        : 'audio/webm'; // fallback

      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;

      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunks.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        try {
          setIsProcessing(true);

          // Create blob from chunks
          const blob = new Blob(chunks, { type: mimeType });

          // Convert to base64
          const reader = new FileReader();
          reader.onloadend = () => {
            try {
              const base64 = (reader.result as string).split(',')[1];

              // Send to backend for STT
              if (socketRef.current?.connected) {
                socketRef.current.emit('voice_audio', {
                  audio: base64,
                  final: true,
                });
              } else {
                // Fallback: use Web Speech API if available
                fallbackWebSpeechSTT();
              }
            } catch (err) {
              console.error('[Voice] Error processing audio data:', err);
              setError('Audio processing failed');
              setIsProcessing(false);
            }
          };
          reader.onerror = () => {
            console.error('[Voice] FileReader error');
            setError('Failed to read audio data');
            setIsProcessing(false);
          };
          reader.readAsDataURL(blob);
        } catch (err) {
          console.error('[Voice] Error in onstop handler:', err);
          setError('Recording stop error');
          setIsProcessing(false);
        } finally {
          // Cleanup stream
          if (streamRef.current) {
            streamRef.current.getTracks().forEach((track) => {
              try {
                track.stop();
              } catch (err) {
                console.warn('[Voice] Error stopping track:', err);
              }
            });
            streamRef.current = null;
          }
        }
      };

      mediaRecorder.onerror = (e) => {
        console.error('[Voice] MediaRecorder error:', e);
        setError('Recording error occurred');
        stopListening();
      };

      // Start recording
      mediaRecorder.start();
      setIsListening(true);

      // Notify backend
      if (socketRef.current) {
        socketRef.current.emit('voice_start');
      }

    } catch (err: any) {
      console.error('[Voice] Mic access denied:', err);
      setError(err.message || 'Microphone access denied');
      setIsListening(false);
    }
  }, [disabled, isListening, isProcessing, analyzeAudio]);

  const stopListening = useCallback(() => {
    if (!isListening || !mediaRecorderRef.current) return;

    try {
      // Stop recording
      mediaRecorderRef.current.stop();
      setIsListening(false);
      setIntensity(0);

      // Cancel animation frame
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
      }

      // Close audio context
      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }

      // Notify backend
      if (socketRef.current) {
        socketRef.current.emit('voice_stop');
      }
    } catch (err) {
      console.error('[Voice] Error stopping listening:', err);
      setError('Error stopping recording');
    }
  }, [isListening]);

  // Fallback: Web Speech API for browsers that support it
  const fallbackWebSpeechSTT = useCallback(() => {
    if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
      setError('Speech recognition not supported');
      setIsProcessing(false);
      return;
    }

    try {
      const SpeechRecognition =
        (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();

      recognition.continuous = false;
      recognition.interimResults = false;
      recognition.lang = 'en-US';

      recognition.onresult = (event: any) => {
        try {
          const transcript = event.results[0]
            ? event.results[0][0].transcript
            : '';
          if (transcript) {
            onTranscript(transcript);
          }
          setIsProcessing(false);
        } catch (err) {
          console.error('[Voice] Error in speech recognition result:', err);
          setError('Speech recognition processing error');
          setIsProcessing(false);
        }
      };

      recognition.onerror = (event: any) => {
        console.error('[Voice] Speech recognition error:', event.error);
        setError(`Speech recognition error: ${event.error}`);
        setIsProcessing(false);
      };

      recognition.onend = () => {
        setIsProcessing(false);
      };

      recognition.start();
    } catch (err) {
      console.error('[Voice] Error initializing speech recognition:', err);
      setError('Failed to initialize speech recognition');
      setIsProcessing(false);
    }
  }, [onTranscript]);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      // Ensure all resources are cleaned up
      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }

      if (audioContextRef.current) {
        audioContextRef.current.close();
      }

      if (streamRef.current) {
        streamRef.current.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  // MARKER_FIX_EVENT_LISTENERS_START
  const handleClick = useCallback(() => {
    if (isListening) {
      stopListening();
    } else {
      startListening();
    }
  }, [isListening, startListening, stopListening]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Enter' || e.key === ' ') {
      e.preventDefault();
      handleClick();
    }
  }, [handleClick]);
  // MARKER_FIX_EVENT_LISTENERS_END

  // Render logic would continue here...
  // For brevity, showing only the fixed event handler parts
}
