  // ... existing state properties ...

  // Add favorited chats set to track which chats are favorites
  favoritedChatIds: Set<string>;

  // Add toggleFavorite action
  toggleFavorite: (chat_id: string) => Promise<void>;

  // Add setter for favorited chats (for initial load)
  setFavoritedChats: (chatIds: string[]) => void;
}

// ... existing useStore implementation ...

export const useStore = create<TreeState>()(
  immer((set, get) => ({
    // ... existing state and actions ...

    // Initialize favorited chats set
    favoritedChatIds: new Set<string>(),

    // Set favorited chats (used for initial load from backend)
    setFavoritedChats: (chatIds) => set((state) => {
      state.favoritedChatIds = new Set(chatIds);
    }),

    // Toggle favorite status of a chat with optimistic UI update
    toggleFavorite: async (chat_id: string) => {
      const isCurrentlyFavorited = get().favoritedChatIds.has(chat_id);

      // Optimistic update - immediately toggle UI state
      set((state) => {
        if (isCurrentlyFavorited) {
          state.favoritedChatIds.delete(chat_id);
        } else {
          state.favoritedChatIds.add(chat_id);
        }
      });

      try {
        // Make API call to persist favorite status
        const response = await fetch(`/api/chat/${chat_id}/favorite`, {
