              chatNode.metadata = {};
            }
            chatNode.metadata.is_favorite = !isCurrentlyFavorited;
          }
        });
      } catch (error) {
        // Rollback optimistic update on error
        set((state) => {
          if (isCurrentlyFavorited) {
            state.favoritedChatIds.add(chat_id);
          } else {
            state.favoritedChatIds.delete(chat_id);
          }
