// file: client/src/components/DropZoneRouter.tsx
import React, { useState, useCallback } from 'react';
import { useStore } from '../store/useStore';
import { FilePreview } from './ui/FilePreview';
import { Panel } from './ui/Panel';

// MARKER_102_2_START
export const DropZoneRouter: React.FC = () => {
  const { currentView, setCurrentView, selectedFile, setSelectedFile } = useStore();
  const [isDragging, setIsDragging] = useState(false);

  const handleViewChange = useCallback((view: string) => {
    // Fixed: Added proper event handling to prevent default behavior
    setCurrentView(view);

    // Fixed: Ensure file selection is cleared when changing views
    if (view !== 'file-preview') {
      setSelectedFile(null);
    }
  }, [setCurrentView, setSelectedFile]);

  const handleFileSelect = useCallback((file: File | null) => {
    // Fixed: Properly handle file selection with null checks
    if (file) {
      setSelectedFile(file);
      setCurrentView('file-preview');
    }
  }, [setSelectedFile, setCurrentView]);

  // Fixed: Added proper drag event handlers with preventDefault
  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    e.stopPropagation();
    setIsDragging(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileSelect(e.dataTransfer.files[0]);
      e.dataTransfer.clearData();
    }
  }, [handleFileSelect]);

  return (
    <div 
      className="drop-zone-router"
      onDragOver={handleDragOver}
      onDragLeave={handleDragLeave}
      onDrop={handleDrop}
    >
      {currentView === 'file-preview' && selectedFile ? (
        <FilePreview file={selectedFile} onBack={() => handleViewChange('main')} />
      ) : (
        <Panel 
          isDragging={isDragging}
          onFileSelect={handleFileSelect}
          onViewChange={handleViewChange}
        />
      )}
    </div>
  );
};
// MARKER_102_2_END
