// file: client/src/components/jarvis/JarvisMemoryExplorer.tsx
import React, { useState, useEffect } from 'react';
import { useStore } from '../../store/useStore';
import { MemoryNode } from '../../types/agent';

interface MemoryExplorerProps {
  agentId: string;
}

export const JarvisMemoryExplorer: React.FC<MemoryExplorerProps> = ({ agentId }) => {
  const [memoryNodes, setMemoryNodes] = useState<MemoryNode[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const { socket } = useStore();

  // MARKER_102_3_START
  useEffect(() => {
    if (!agentId) return;

    const fetchMemoryData = async () => {
      try {
        setLoading(true);
        // Fix: Ensure proper error handling and data validation
        socket.emit('agent_memory_request', { agentId }, (response: any) => {
          if (response.error) {
            setError(response.error);
            setMemoryNodes([]);
          } else if (response.data && Array.isArray(response.data)) {
            // Fix: Validate memory node structure before setting state
            const validNodes = response.data.filter((node: any) => 
              node.id && node.content && typeof node.timestamp === 'number'
            );
            setMemoryNodes(validNodes);
            setError(null);
          } else {
            setMemoryNodes([]);
            setError('Invalid memory data received');
          }
          setLoading(false);
        });
      } catch (err) {
        setError('Failed to fetch agent memory');
        setLoading(false);
        setMemoryNodes([]);
      }
    };

    fetchMemoryData();
  }, [agentId, socket]);
  // MARKER_102_3_END

  if (loading) return <div className="memory-explorer-loading">Loading memory...</div>;
  if (error) return <div className="memory-explorer-error">Error: {error}</div>;

  return (
    <div className="jarvis-memory-explorer">
      <h3>Agent Memory Explorer</h3>
      <div className="memory-nodes-container">
        {memoryNodes.map((node) => (
          <div key={node.id} className="memory-node">
            <div className="memory-timestamp">
              {new Date(node.timestamp).toLocaleString()}
            </div>
            <div className="memory-content">
              {node.content}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
