// MARKER_102_2_START
export const diagnoseUIInteractions = (element: HTMLElement | null) => {
  if (!element) {
    console.warn('No element provided for diagnosis');
    return;
  }

  // Check if element is disabled
  if (element.hasAttribute('disabled')) {
    console.warn('Element is disabled:', element);
  }

  // Check pointer events
  const pointerEvents = window.getComputedStyle(element).pointerEvents;
  if (pointerEvents === 'none') {
    console.warn('Element has pointer-events: none', element);
  }

  // Check z-index
  const zIndex = window.getComputedStyle(element).zIndex;
  if (zIndex === '0' || zIndex === 'auto') {
    console.info('Element has low z-index:', zIndex, element);
  }

  // Check if element is hidden
  const display = window.getComputedStyle(element).display;
  const visibility = window.getComputedStyle(element).visibility;
  if (display === 'none' || visibility === 'hidden') {
    console.warn('Element is hidden:', { display, visibility }, element);
  }

  // Check event listeners
  const listeners = getEventListeners(element);
  if (Object.keys(listeners).length === 0) {
    console.warn('No event listeners found on element', element);
  } else {
    console.info('Event listeners found:', listeners);
  }

  // Check parent elements for issues
  let parent = element.parentElement;
  while (parent) {
    const parentPointerEvents = window.getComputedStyle(parent).pointerEvents;
    if (parentPointerEvents === 'none') {
      console.warn('Parent element has pointer-events: none', parent);
    }
    parent = parent.parentElement;
  }
};

// Helper function to get event listeners (Chrome DevTools only)
const getEventListeners = (element: HTMLElement): Record<string, any> => {
  // @ts-ignore - only available in Chrome DevTools
  if (typeof window.getEventListeners === 'function') {
    // @ts-ignore
    return window.getEventListeners(element);
  }
  return {};
};

export const checkConsoleErrors = () => {
  if (console.errors && console.errors.length > 0) {
    console.warn('Console errors detected:', console.errors);
  }
};

export const diagnoseAgentCardInteractions = (cardId: string) => {
  const cardElement = document.getElementById(cardId);
  console.group(`Diagnosing Agent Card: ${cardId}`);
  diagnoseUIInteractions(cardElement);
  checkConsoleErrors();
  console.groupEnd();
};
