import { useState, useEffect, useCallback, useRef } from 'react';
import { ArrowDown } from 'lucide-react';

interface ScrollToBottomButtonProps {
  messagesContainerRef: React.RefObject<HTMLDivElement>;
  onScrollToBottom: () => void;
}

export function ScrollToBottomButton({ 
  messagesContainerRef, 
  onScrollToBottom 
}: ScrollToBottomButtonProps) {
  const [isAtBottom, setIsAtBottom] = useState(true);
  const [canScroll, setCanScroll] = useState(false);
  const scrollCheckRef = useRef<number | null>(null);

  // MARKER_102_3_START: Isolated scroll position tracking with proper cleanup
  const checkScrollPosition = useCallback(() => {
    if (!messagesContainerRef.current) return;

    const { scrollTop, scrollHeight, clientHeight } = messagesContainerRef.current;
    const isCurrentlyAtBottom = scrollHeight <= scrollTop + clientHeight + 10;
    const isCurrentlyScrollable = scrollHeight > clientHeight;

    // Only update state if values have changed to prevent unnecessary re-renders
    setIsAtBottom(prev => {
      if (prev !== isCurrentlyAtBottom) return isCurrentlyAtBottom;
      return prev;
    });

    setCanScroll(prev => {
      if (prev !== isCurrentlyScrollable) return isCurrentlyScrollable;
      return prev;
    });
  }, [messagesContainerRef]);

  // Throttled scroll handler to prevent performance issues
  const handleScroll = useCallback(() => {
    if (scrollCheckRef.current) {
      cancelAnimationFrame(scrollCheckRef.current);
    }

    scrollCheckRef.current = requestAnimationFrame(() => {
      checkScrollPosition();
    });
  }, [checkScrollPosition]);

  useEffect(() => {
    const container = messagesContainerRef.current;
    if (!container) return;

    // Add scroll listener
    container.addEventListener('scroll', handleScroll, { passive: true });

    // Initial check
    checkScrollPosition();

    // MutationObserver to detect content changes
    const observer = new MutationObserver(() => {
      checkScrollPosition();
    });

    observer.observe(container, {
      childList: true,
      subtree: true,
    });

    return () => {
      container.removeEventListener('scroll', handleScroll);
      observer.disconnect();

      if (scrollCheckRef.current) {
        cancelAnimationFrame(scrollCheckRef.current);
      }
    };
  }, [messagesContainerRef, handleScroll, checkScrollPosition]);
  // MARKER_102_3_END

  // MARKER_102_3_START: Pure button component with explicit event handling
  const handleClick = useCallback((e: React.MouseEvent<HTMLButtonElement>) => {
    e.preventDefault();
    e.stopPropagation();
    onScrollToBottom();
  }, [onScrollToBottom]);

  if (isAtBottom || !canScroll) {
    return null;
  }

  return (
    <button
      onClick={handleClick}
      aria-label="Scroll to bottom"
      style={{
        position: 'absolute',
        bottom: '90px',
        right: '24px',
        zIndex: 10,
        width: '36px',
