Based on my analysis of the VoiceButton component, I can see there might be issues with the button implementation related to state management and event handling. Here's my fix:

```typescript
// file: client/src/components/voice/VoiceButton.tsx

import { useState, useCallback, useRef, useEffect } from 'react';
import { Mic, MicOff, Volume2, Loader2 } from 'lucide-react';
import { VoiceWave } from './VoiceWave';
import { getSocketUrl } from '../../config/api.config';

interface VoiceButtonProps {
  onTranscript: (text: string) => void;
  disabled?: boolean;
  compact?: boolean;
}

interface VoiceSocket {
  emit: (event: string, data?: any) => void;
  on: (event: string, callback: (data: any) => void) => void;
  off: (event: string, callback?: (data: any) => void) => void;
  connected: boolean;
}

// MARKER_FIX_START
export function VoiceButton({
  onTranscript,
  disabled = false,
  compact = false,
}: VoiceButtonProps) {
  const [isListening, setIsListening] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [intensity, setIntensity] = useState(0);
  const [error, setError] = useState<string | null>(null);

  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const animationFrameRef = useRef<number | null>(null);
  const socketRef = useRef<VoiceSocket | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  // Fixed button click handler with proper state checks
  const handleButtonClick = useCallback(async () => {
    // Prevent multiple simultaneous actions
    if (disabled || isProcessing) return;

    if (isListening) {
      stopListening();
    } else {
      await startListening();
    }
  }, [disabled, isListening, isProcessing, startListening, stopListening]);

  // Improved socket connection handling
  useEffect(() => {
    const initializeSocket = () => {
      if (typeof window !== 'undefined' && (window as any).io) {
        const io = (window as any).io;
        const socketUrl = getSocketUrl();

        // Only create new connection if one doesn't exist
        if (!socketRef.current) {
          socketRef.current = io(socketUrl, {
            transports: ['websocket', 'polling'],
            reconnection: true,
          });
        }
      }
    };

    initializeSocket();

    return () => {
      if (socketRef.current) {
        socketRef.current.off('voice_transcribed');
        socketRef.current.off('voice_status');
        socketRef.current.off('voice_error');
      }
    };
  }, []);

  // Enhanced socket event listeners with better error handling
  useEffect(() => {
    const socket = socketRef.current;
    if (!socket) return;

    const handleTranscribed = (data: { text: string; final: boolean }) => {
      try {
        if (data.text) {
          onTranscript(data.text);
        }
        setIsProcessing(false);
      } catch (err) {
        console.error('[Voice] Transcription handler error:', err);
        setError('Transcription processing failed');
      }
    };

    const handleStatus = (data: { status: string }) => {
      try {
        switch (data.status) {
          case 'speaking':
            setIsSpeaking(true);
            break;
          case 'idle':
            setIsSpeaking(false);
            setIsListening(false);
            break;
          case 'listening':
            setIsListening(true);
            break;
          default:
            break;
        }
      } catch (err) {
        console.error('[Voice] Status handler error:', err);
      }
    };

    const handleError = (data: { error: string }) => {
      setError(data.error || 'Unknown voice error');
      setIsProcessing(false);
      setIsListening(false);

      // Clear error after delay
      setTimeout(() => setError(null), 3000);
    };

    socket.on('voice_transcribed', handleTranscribed);
    socket.on('voice_status', handleStatus);
    socket.on('voice_error', handleError);

    return () => {
      socket.off('voice_transcribed', handleTranscribed);
      socket.off('voice_status', handleStatus);
      socket.off('voice_error', handleError);
    };
  }, [onTranscript]);

  // Fixed audio analysis with proper cleanup
  const analyzeAudio = useCallback((stream: MediaStream) => {
    try {
      if (audioContextRef.current) {
        audioContextRef.current.close();
      }

      audioContextRef.current = new AudioContext();
      analyserRef.current = audioContextRef.current.createAnalyser();

      const source = audioContextRef.current.createMediaStreamSource(stream);
      source.connect(analyserRef.current);

      analyserRef.current.fftSize = 256;
      const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);

      const updateIntensity = () => {
        if (!analyserRef.current || !isListening) {
          setIntensity(0);
          return;
        }

        analyserRef.current.getByteFrequencyData(dataArray);
        const average = dataArray.reduce((a, b) => a + b, 0) / dataArray.length;
        setIntensity(Math.min(1, average / 128));

        animationFrameRef.current = requestAnimationFrame(updateIntensity);
      };

      updateIntensity();
    } catch (e) {
      console.error('[Voice] Audio analysis error:', e);
      setError('Audio analysis failed');
    }
  }, [isListening]);

  const startListening = useCallback(async () => {
    if (disabled || isListening || isProcessing) return;

    setError(null);

    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        audio: {
          echoCancellation: true,
          noiseSuppression: true,
          autoGainControl: true,
        },
      });

      streamRef.current = stream;
      analyzeAudio(stream);

      const mimeType = MediaRecorder.isTypeSupported('audio/webm')
        ? 'audio/webm'
        : 'audio/mp4';

      const mediaRecorder = new MediaRecorder(stream, { mimeType });
      mediaRecorderRef.current = mediaRecorder;

      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) {
          chunks.push(e.data);
        }
      };

      mediaRecorder.onstop = async () => {
        setIsProcessing(true);

        try {
          const blob = new Blob(chunks, { type: mimeType });
          const reader = new FileReader();

          reader.onloadend = () => {
            try {
              const base64 = (reader.result as string).split(',')[1];

              if (socketRef.current?.connected) {
                socketRef.current.emit('voice_audio', {
                  audio: base64,
                  final: true,
                });
              } else {
                fallbackWebSpeechSTT();
              }
            } catch (err) {
              console.error('[Voice] Audio processing error:', err);
              setError('Audio processing failed');
              setIsProcessing(false);
            }
          };

          reader.readAsDataURL(blob);
        } catch (err) {
          console.error('[Voice] Blob processing error:', err);
          setError('Audio processing failed');
          setIsProcessing(false);
        }

        // Cleanup stream
        try {
          stream.getTracks().forEach((track) => {
            if (track.readyState === 'live') {
              track.stop();
            }
          });
          streamRef.current = null;
        } catch (err) {
          console.warn('[Voice] Stream cleanup warning:', err);
        }
      };

      mediaRecorder.start();
      setIsListening(true);

      if (socketRef.current?.connected) {
        socketRef.current.emit('voice_start');
      }

    } catch (err) {
      console.error('[Voice] Mic access denied:', err);
      setError('Microphone access denied');
      setIsListening(false);
    }
  }, [disabled, isListening, isProcessing, analyzeAudio]);

  const stopListening = useCallback(() => {
    if (!isListening || !mediaRecorderRef.current) return;

    try {
      mediaRecorderRef.current.stop();
      setIsListening(false);
      setIntensity(0);

      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
        animationFrameRef.current = null;
      }

      if (audioContextRef.current) {
        audioContextRef.current.close();
        audioContextRef.current = null;
      }

      if (socketRef.current?.connected) {
        socketRef.current.emit('voice_stop');
      }
    } catch (err) {
      console.error('[Voice] Stop listening error:', err);
      setError('Failed to stop recording');
    }
  }, [isListening]);

  const fallbackWebSpeechSTT = useCallback(() => {
    if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
      setError('Speech recognition not supported');
      setIsProcessing(false);
      return;
    }

    try {
      const SpeechRecognition =
        (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
      const recognition = new SpeechRecognition();

      recognition.continuous = false;
      recognition.interimResults = false;
      recognition.lang = 'en-US';

      recognition.onresult = (event: any) => {
        try {
          const transcript = event.results[0][0].transcript;
          onTranscript(transcript);
        } catch (err) {
          console.error('[Voice] Speech recognition result error:', err);
          setError('Speech recognition processing failed');
        } finally {
          setIsProcessing(false);
        }
      };

      recognition.onerror = (event: any) => {
        console.error('[Voice] Speech recognition error:', event.error);
        setError(`Speech recognition error: ${event.error}`);
        setIsProcessing(false);
      };

      recognition.onend = () => {
        setIsProcessing(false);
      };

      recognition.start();
    } catch (err) {
      console.error('[Voice] Speech recognition init error:', err);
      setError('Speech recognition initialization failed');
      setIsProcessing(false);
    }
  }, [onTranscript]);

  // Improved cleanup on unmount
  useEffect(() => {
    return () => {
      // Ensure all resources are cleaned up
      if (mediaRecorderRef.current && isListening) {
        try {
          mediaRecorderRef.current.stop();
        } catch (err) {
          console.warn('[Voice] MediaRecorder cleanup warning:', err);
        }
      }

      if (animationFrameRef.current) {
        cancelAnimationFrame(animationFrameRef.current);
      }

      if (audioContextRef.current) {
        audioContextRef.current.close();
      }

      if (streamRef.current) {
        try {
          streamRef.current.getTracks().forEach(track => {
            if (track.readyState === 'live') {
              track.stop();
            }
          });
        } catch (err) {
          console.warn('[Voice] Stream cleanup warning:', err);
        }
      }
    };
  }, [isListening]);

  // Render button with improved accessibility and state handling
  return (
    <button
      type="button"
      onClick={handleButtonClick}
      disabled={disabled || isProcessing}
      aria-label={isListening ? "Stop listening" : "Start voice input"}
      aria-pressed={isListening}
      className={`
        relative flex items-center justify-center rounded-full
        ${compact ? 'w-8 h-8' : 'w-12 h-12'}
        ${disabled ? 'opacity-50 cursor-not-allowed' : 'hover:opacity-90 active:scale-95'}
        ${isListening ? 'bg-red-500 text-white' : 'bg-blue-500 text-white'}
        ${isProcessing ? 'animate-pulse' : ''}
        transition-all duration-200 ease-in-out
        focus:outline-none focus:ring-2 focus:ring-blue-300
      `}
    >
      {isProcessing ? (
        <Loader2 className={`w-4 h-4 ${compact ? 'w-4 h-4' : 'w-6 h-6'} animate-spin`} />
      ) : isSpeaking ? (
        <Volume2 className={compact ? 'w-4 h-4' : 'w-6 h-6'} />
      ) : isListening ? (
        <MicOff className={compact ? 'w-4 h-4' : 'w-6 h-6'} />
      ) : (
        <Mic className={compact ? 'w-4 h-4' : 'w-6 h-6'} />
      )}

      {!compact && isListening && (
        <VoiceWave 
          intensity={intensity} 
          className="absolute inset-0 -m-1" 
        />
      )}

      {error && (
        <div className="absolute -bottom-8 left-1/2 transform -translate-x-1/2 bg-red-500 text-white text-xs px-2 py-1 rounded whitespace-nowrap">
          {error}
        </div>
      )}
    </button>
  );
}
// MARKER_FIX_END
