import { useEffect, useRef } from 'react';

/**
 * Hook to diagnose JavaScript event handling issues
 * Logs event listener registration and helps identify potential problems
 */
export const useEventDiagnostics = () => {
  const diagnosticsRef = useRef({
    listeners: [] as string[],
    errors: [] as string[],
  });

  // MARKER_102.2_START
  useEffect(() => {
    // Check for common JavaScript errors that prevent event handlers
    const handleError = (event: ErrorEvent) => {
      console.error('JavaScript Error Detected:', {
        message: event.message,
        filename: event.filename,
        lineno: event.lineno,
        colno: event.colno,
        error: event.error
      });

      diagnosticsRef.current.errors.push(event.message);
    };

    const handleUnhandledRejection = (event: PromiseRejectionEvent) => {
      console.error('Unhandled Promise Rejection:', event.reason);
      diagnosticsRef.current.errors.push(`Promise rejection: ${event.reason}`);
    };

    // Add global error handlers
    window.addEventListener('error', handleError);
    window.addEventListener('unhandledrejection', handleUnhandledRejection);

    // Log when component mounts
    console.log('Event diagnostics initialized');

    return () => {
      window.removeEventListener('error', handleError);
      window.removeEventListener('unhandledrejection', handleUnhandledRejection);
    };
  }, []);

  const logEventListener = (element: HTMLElement, event: string, handler: EventListener) => {
    const listenerId = `${element.tagName}.${Array.from(element.classList).join('.')}#${element.id} - ${event}`;
    diagnosticsRef.current.listeners.push(listenerId);
    console.log(`Event listener added: ${listenerId}`);
  };

  const getDiagnostics = () => {
    return {
      listeners: diagnosticsRef.current.listeners,
      errors: diagnosticsRef.current.errors,
      hasErrors: diagnosticsRef.current.errors.length > 0
    };
  };
  // MARKER_102.2_END

  return {
    logEventListener,
    getDiagnostics
  };
};

export default useEventDiagnostics;

