    // Check for Authorization header
    const authHeader = headers.get('Authorization');
    if (authHeader && authHeader.startsWith('Bearer ')) {
      result.authHeader = authHeader;
      result.hasToken = true;
      result.tokenLocation = 'header';
    }

    // Check for CORS headers in preflight
    if (options.method === 'OPTIONS') {
      result.corsHeadersPresent = headers.has('Access-Control-Allow-Origin');
    }

    return originalFetch.apply(this, args);
  };

  // Monitor XMLHttpRequest for older requests
  const originalXHROpen = XMLHttpRequest.prototype.open;
  XMLHttpRequest.prototype.open = function(...args) {
    const headers = (this as any)._requestHeaders || {};
    const authHeader = headers['Authorization'] || headers['authorization'];
    if (authHeader && authHeader.startsWith('Bearer ')) {
      result.authHeader = authHeader;
      result.hasToken = true;
      result.tokenLocation = 'header';
    }
    return originalXHROpen.apply(this, args);
  };

  // Listen for network errors
  window.addEventListener('error', (event) => {
    if (event.error && event.error.message) {
      const msg = event.error.message.toLowerCase();
      if (msg.includes('cors')) {
        result.errorType = 'CORS';
      }
    }
  });

  return result;
};

