// file: client/src/services/authService.ts
import { io } from 'socket.io-client';
import { API_BASE_URL } from '../config/api';

class AuthService {
  private token: string | null = null;
  private socket: any = null;

  // Store token securely (in httpOnly cookie via backend when possible)
  setToken(token: string): void {
    this.token = token;
    // In a real implementation, we'd prefer httpOnly cookies set by backend
    // For now, using secure storage with additional protections
    if (typeof window !== 'undefined') {
      try {
        // Store in sessionStorage for better security than localStorage
        sessionStorage.setItem('authToken', token);
      } catch (e) {
        console.warn('Could not store token in sessionStorage');
      }
    }
  }

  // Retrieve token from secure storage
  getToken(): string | null {
    if (this.token) {
      return this.token;
    }

    if (typeof window !== 'undefined') {
      try {
        const token = sessionStorage.getItem('authToken');
        this.token = token;
        return token;
      } catch (e) {
        console.warn('Could not retrieve token from sessionStorage');
      }
    }

    return null;
  }

  // Clear token from storage
  clearToken(): void {
    this.token = null;
    if (typeof window !== 'undefined') {
      try {
        sessionStorage.removeItem('authToken');
      } catch (e) {
        console.warn('Could not remove token from sessionStorage');
      }
    }
  }

  // Create authenticated API request headers
  getAuthHeaders(): Record<string, string> {
    const token = this.getToken();
    const headers: Record<string, string> = {
      'Content-Type': 'application/json',
    };

    if (token) {
      headers['Authorization'] = `Bearer ${token}`;
    }

    return headers;
  }

  // Initialize socket connection with authentication
  initializeSocket(): any {
    const token = this.getToken();
    this.socket = io(API_BASE_URL, {
      transports: ['websocket'],
      auth: token ? { token } : {},
    });

    return this.socket;
  }

  // Get socket instance
  getSocket(): any {
    return this.socket;
  }

  // Authenticated fetch wrapper
  async authenticatedFetch(url: string, options: RequestInit = {}): Promise<Response> {
    const headers = {
      ...this.getAuthHeaders(),
      ...options.headers,
    };

    const response = await fetch(`${API_BASE_URL}${url}`, {
      ...options,
      headers,
    });

    // Handle token expiration
    if (response.status === 401) {
      this.clearToken();
      // Redirect to login or emit event
      window.dispatchEvent(new CustomEvent('auth-expired'));
    }

    return response;
  }
}

// MARKER_102.2_START
export const authService = new AuthService();
// MARKER_102.2_END
