import React, { useEffect, useState } from 'react';
import { fetchPipelineHistory } from '../../api/monitoring';
import { PipelineHistoryEntry } from '../../types/monitoring';

const MCCStatsPanel: React.FC = () => {
  const [bronzeRatio, setBronzeRatio] = useState<number>(0);
  const [silverRatio, setSilverRatio] = useState<number>(0);
  const [isLoading, setIsLoading] = useState<boolean>(true);

  useEffect(() => {
    const loadPipelineData = async () => {
      try {
        setIsLoading(true);
        const historyData: PipelineHistoryEntry[] = await fetchPipelineHistory();

        // Calculate bronze vs silver usage from pipeline history
        let bronzeCount = 0;
        let silverCount = 0;

        historyData.forEach(entry => {
          if (entry.material_used === 'bronze') {
            bronzeCount += entry.quantity;
          } else if (entry.material_used === 'silver') {
            silverCount += entry.quantity;
          }
        });

        const total = bronzeCount + silverCount;
        if (total > 0) {
          setBronzeRatio((bronzeCount / total) * 100);
          setSilverRatio((silverCount / total) * 100);
        } else {
          setBronzeRatio(0);
          setSilverRatio(0);
        }
      } catch (error) {
        console.error('Failed to load pipeline history:', error);
      } finally {
        setIsLoading(false);
      }
    };

    loadPipelineData();
  }, []);

  // MARKER_102.2_START
  return (
    <div className="stats-panel">
      <h3>MCC Production Stats</h3>
      {isLoading ? (
        <div>Loading stats...</div>
      ) : (
        <div className="material-ratio-container">
          <div className="ratio-item">
            <div className="ratio-label">Bronze Usage</div>
            <div className="ratio-bar-container">
              <div 
