import React, { useState } from 'react';
import { useStore } from '../../store/useStore';

interface StarToggleProps {
  itemId: string;
  isFavorite: boolean;
  nodePath?: string;
  agent?: string;
}

const StarToggle: React.FC<StarToggleProps> = ({ 
  itemId, 
  isFavorite,
  nodePath = '',
  agent = 'default'
}) => {
  const [isToggled, setIsToggled] = useState(isFavorite);
  const { addFavorite, removeFavorite } = useStore();

  const handleToggle = async () => {
    const newStatus = !isToggled;
    setIsToggled(newStatus);

    try {
      // Call the favorites API endpoint
      const response = await fetch('http://localhost:5001/favorites/toggle', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          message_id: itemId,
          node_path: nodePath,
          active: newStatus,
          agent: agent
        }),
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const result = await response.json();

      // Update local state based on API response
      if (newStatus) {
        await addFavorite(itemId);
      } else {
        await removeFavorite(itemId);
      }
    } catch (error) {
      // Revert the toggle on error
      setIsToggled(!newStatus);
      console.error('Failed to update favorite status:', error);
    }
  };

  return (
    <button 
      onClick={handleToggle}
      className={`star-toggle ${isToggled ? 'favorited' : ''}`}
      aria-label={isToggled ? 'Remove from favorites' : 'Add to favorites'}
    >
      {isToggled ? '⭐' : '☆'}
    </button>
  );
};

export default StarToggle;

