"""
Favorite utilities for managing user favorites.
This module implements a simple dictionary-based storage for favorites.
"""

from typing import Dict, List, Set
from dataclasses import dataclass
from datetime import datetime


@dataclass
class FavoriteItem:
    """Represents a favorite item with metadata."""
    id: str
    type: str  # 'file', 'folder', 'chat', etc.
    path: str
    name: str
    added_at: datetime


class FavoriteStore:
    """Dictionary-based store for managing favorites."""

    def __init__(self):
        self._favorites: Dict[str, FavoriteItem] = {}

    def add_favorite(self, item: FavoriteItem) -> None:
        """Add a favorite item to the store."""
        self._favorites[item.id] = item

    def remove_favorite(self, item_id: str) -> bool:
        """Remove a favorite item by ID. Returns True if removed, False if not found."""
        if item_id in self._favorites:
            del self._favorites[item_id]
            return True
        return False

    def is_favorite(self, item_id: str) -> bool:
        """Check if an item is favorited."""
        return item_id in self._favorites

    def get_favorite(self, item_id: str) -> FavoriteItem | None:
        """Get a favorite item by ID."""
        return self._favorites.get(item_id)

    def get_all_favorites(self) -> List[FavoriteItem]:
        """Get all favorite items."""
        return list(self._favorites.values())

    def get_favorite_ids(self) -> Set[str]:
        """Get all favorite item IDs."""
        return set(self._favorites.keys())

    def clear_all(self) -> None:
        """Clear all favorites."""
        self._favorites.clear()

    def size(self) -> int:
        """Get the number of favorite items."""
        return len(self._favorites)
