// file: client/src/components/debug/PlaygroundManager.tsx
import { useState, useEffect } from 'react';
import { useStore } from '../../store/useStore';

interface Playground {
  id: string;
  name: string;
  created_at: string;
  status: 'active' | 'inactive';
}

interface PlaygroundResponse {
  playgrounds: Playground[];
  active_count: number;
}

export function PlaygroundManager() {
  const [playgrounds, setPlaygrounds] = useState<Playground[]>([]);
  const [activeCount, setActiveCount] = useState<number>(0);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [pollingInterval, setPollingInterval] = useState<NodeJS.Timeout | null>(null);

  // MARKER_102.4_START: Fetch playground data with polling
  const fetchPlaygrounds = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/debug/playground');
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const data: PlaygroundResponse = await response.json();
      setPlaygrounds(data.playgrounds);
      setActiveCount(data.active_count);
      setError(null);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'An unknown error occurred');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    // Initial fetch
    fetchPlaygrounds();

    // Setup polling interval (5 seconds)
    const interval = setInterval(fetchPlaygrounds, 5000);
    setPollingInterval(interval);

    // Cleanup function
    return () => {
      if (interval) {
        clearInterval(interval);
      }
    };
  }, []);
  // MARKER_102.4_END

  // MARKER_102.4_DESTROY_START: Destroy handler for playgrounds
  const handleDestroyPlayground = async (id: string) => {
    try {
      const response = await fetch(`/api/debug/playground/${id}`, {
        method: 'DELETE',
      });

      if (!response.ok) {
        throw new Error(`Failed to delete playground: ${response.status}`);
      }

      // Refresh the playground list after deletion
      await fetchPlaygrounds();
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to delete playground');
    }
  };
  // MARKER_102.4_DESTROY_END

  if (loading) {
    return <div>Loading playgrounds...</div>;
  }

  if (error) {
    return <div>Error: {error}</div>;
  }

  return (
    <div>
      <h2>Playgrounds ({activeCount} active)</h2>
      <ul>
        {playgrounds.map((playground) => (
          <li key={playground.id}>
            {playground.name} - {playground.status}
            <button onClick={() => handleDestroyPlayground(playground.id)}>
              Delete
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}
