// file: client/src/utils/formatUtils.ts
import { format } from 'date-fns';

/**
 * Formats a timestamp into a relative time string like '2m ago' or '5s ago'
 * @param ms - timestamp in milliseconds
 * @returns formatted relative time string
 */
export function formatRelativeTime(ms: number): string {
  // MARKER_FORMAT_RELATIVE_TIME_START
  const now = Date.now();
  const diffInSeconds = Math.floor((now - ms) / 1000);

  if (diffInSeconds < 60) {
    return `${diffInSeconds}s ago`;
  }

  const diffInMinutes = Math.floor(diffInSeconds / 60);
  if (diffInMinutes < 60) {
    return `${diffInMinutes}m ago`;
  }

  const diffInHours = Math.floor(diffInMinutes / 60);
  if (diffInHours < 24) {
    return `${diffInHours}h ago`;
  }

  const diffInDays = Math.floor(diffInHours / 24);
  return `${diffInDays}d ago`;
  // MARKER_FORMAT_RELATIVE_TIME_END
}

/**
 * Truncates an ID string to a specified maximum length
 * @param id - the ID string to truncate
 * @param maxLen - maximum length of the truncated string (default: 8)
 * @returns truncated ID string with ellipsis if needed
 */
export function truncateId(id: string, maxLen: number = 8): string {
  // MARKER_TRUNCATE_ID_START
  if (!id) return '';

  if (id.length <= maxLen) {
    return id;
  }

  return `${id.substring(0, maxLen)}...`;
  // MARKER_TRUNCATE_ID_END
}
