def _web_search_tavily(query: str, limit: int) -> Tuple[List[Dict[str, Any]], Optional[str]]:
    def _normalize_web_score(raw_score: Any, rank: int) -> float:
        try:
            score = float(raw_score)
        except (TypeError, ValueError):
            # Stable fallback when provider does not return score.
            return max(0.1, 0.75 - (rank * 0.05))

        if score < 0:
            return 0.0
        # Tavily usually returns 0..1, but normalize defensively if scale differs.
        if score > 1.0:
            score = score / 10.0
        return min(score, 1.0)

    # MARKER_102_1_START
    try:
        tavily_key = os.getenv("TAVILY_API_KEY")
        if not tavily_key:
            return [], "tavily api key missing"

        tavily_client = TavilyClient(api_key=tavily_key)
        response = tavily_client.search(query=query, max_results=min(limit, 10))

        results: List[Dict[str, Any]] = []
        seen_urls = set()

        for idx, item in enumerate(response.get("results", [])[:limit]):
            url = item.get("url", "") or ""
            if url and url in seen_urls:
                continue
            if url:
                seen_urls.add(url)

            score = _normalize_web_score(item.get("score", 0.0), idx)
            results.append(
                _normalize_item(
                    source="web_tavily",
                    title=item.get("title", ""),
                    snippet=item.get("content", ""),
                    score=score,
                    url=url,
                )
            )
        return results, None
    except Exception as exc:
        return [], f"tavily error: {exc}"
