    const mins = parseInt(customMinutes, 10);
    if (!Number.isFinite(mins) || mins <= 0) return;
    await updateHeartbeat({ interval: mins * 60 });
    setCustomMinutes('');
  }, [customMinutes, updateHeartbeat]);

