        <div
          style={{
            position: 'absolute',
            top: 'calc(100% + 4px)',
            left: 0,
            background: '#1a1a1a',
            border: '1px solid #333',
            borderRadius: 6,
            zIndex: 1000,
            width: 220,
            fontFamily: 'monospace',
            fontSize: 10,
            color: '#ccc',
            overflow: 'hidden',
          }}
        >
          <button
            onClick={toggleHeartbeat}
            style={{
              width: '100%',
              textAlign: 'left',
              background: 'transparent',
              border: 'none',
              borderBottom: '1px solid #2a2a2a',
              color: '#ddd',
              padding: '8px 10px',
              fontFamily: 'monospace',
              fontSize: 10,
